{
    "data": {
        "type": "instance",
        "attributes": {
            "workflow_id": "{{workflowId}}",
            "started_by": "radicador-001",
            "data": {
                "numero_radicado": "MT-2024-000001",
                "remitente": "Ministerio del Trabajo",
                "remitente_email": "notificaciones@mintrabajo.gov.co",
                "asunto": "Requerimiento de informacion laboral",
                "fecha_radicacion": "2024-12-01T08:30:00Z",
                "fecha_vencimiento": "2024-12-15T17:00:00Z",
                "tipo_tramite": "requerimiento_informacion",
                "prioridad": "alta",
                "descripcion": "Solicitud de informacion sobre contratos laborales vigentes"
            },
            "variables": {
                "tiempo_total_dias": 10,
                "etapa_actual": "radicacion",
                "requiere_clonacion": false,
                "rechazos_clonacion_count": 0,
                "rechazos_escalamiento_count": 0
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "enviar_a_asignador",
            "actor_id": "radicador-001",
            "reason": "Tramite radicado correctamente, enviando a asignacion",
            "metadata": {
                "verificacion_documentos": true,
                "documentos_completos": true
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "iniciar_asignacion",
            "actor_id": "asignador-001",
            "reason": "Iniciando parametrizacion de tiempos y etapas procesales"
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "asignar_abogado",
            "actor_id": "asignador-001",
            "reason": "Asignando tramite al abogado gestionador",
            "data": {
                "abogado_gestionador_id": "abogado-gestionador-001",
                "abogado_gestionador_nombre": "Dr. Juan Perez",
                "tiempo_gestion": "5d",
                "etapas_procesales": ["analisis", "elaboracion", "revision"],
                "instrucciones": "Revisar contratos laborales y preparar respuesta"
            },
            "metadata": {
                "fecha_asignacion": "2024-12-01T10:00:00Z",
                "fecha_limite_gestion": "2024-12-06T17:00:00Z"
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "enviar_a_revision",
            "actor_id": "abogado-gestionador-001",
            "reason": "Documento de respuesta listo para revision",
            "data": {
                "documento_salida": "DOC-SALIDA-2024-001",
                "abogado_revisor_id": "abogado-revisor-001",
                "abogado_aprobador_id": "abogado-aprobador-001",
                "resumen_respuesta": "Se adjunta informacion de contratos laborales solicitada"
            },
            "metadata": {
                "paginas_documento": 15,
                "anexos": 3
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "aprobar_revision",
            "actor_id": "abogado-revisor-001",
            "reason": "Documento revisado y aprobado",
            "feedback": "El documento cumple con todos los requisitos de forma y fondo.",
            "metadata": {
                "fecha_revision": "2024-12-05T14:00:00Z",
                "observaciones": "Excelente trabajo"
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "aprobar_tramite",
            "actor_id": "abogado-aprobador-001",
            "reason": "Tramite aprobado y respuesta enviada al Ministerio del Trabajo",
            "data": {
                "documento_salida": "DOC-SALIDA-2024-001",
                "numero_respuesta": "RESP-MT-2024-001",
                "fecha_envio_respuesta": "2024-12-06T16:00:00Z"
            },
            "feedback": "Respuesta enviada exitosamente al remitente.",
            "metadata": {
                "medio_envio": "correo_electronico",
                "confirmacion_entrega": true
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "rechazar_revision",
            "actor_id": "abogado-revisor-001",
            "reason": "El documento requiere correcciones",
            "feedback": "Por favor corregir:\n1. Formato de fechas incorrecto en pagina 5\n2. Falta firma del representante legal\n3. Revisar ortografia en seccion de conclusiones",
            "data": {
                "comentarios_rechazo": "Se requieren correcciones menores antes de aprobar",
                "secciones_a_corregir": ["pagina_5", "firma", "conclusiones"]
            },
            "metadata": {
                "fecha_rechazo": "2024-12-05T14:00:00Z",
                "prioridad_correccion": "media"
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "subsanar_y_reenviar",
            "actor_id": "abogado-gestionador-001",
            "reason": "Correcciones realizadas, reenviando a revision",
            "feedback": "Se realizaron las siguientes correcciones:\n1. Formato de fechas corregido\n2. Se agrego firma del representante legal\n3. Ortografia revisada y corregida",
            "data": {
                "documento_salida": "DOC-SALIDA-2024-001-v2",
                "version_documento": 2
            },
            "metadata": {
                "fecha_correccion": "2024-12-05T16:00:00Z",
                "cambios_realizados": true
            }
        }
    }
}

{
    "data": {
        "type": "clone-request",
        "attributes": {
            "assignees": [
                {
                    "user_id": "abogado-clonado-001",
                    "office_id": "oficina-juridica"
                },
                {
                    "user_id": "abogado-clonado-002",
                    "office_id": "oficina-rrhh"
                }
            ],
            "consolidator_id": "abogado-gestionador-001",
            "reason": "Se requiere informacion de contratos laborales de las areas Juridica y RRHH para completar la respuesta al Ministerio del Trabajo.",
            "timeout_duration": "3d",
            "metadata": {
                "documentos_solicitados": [
                    "Listado de contratos vigentes",
                    "Estadisticas de contratacion"
                ],
                "urgencia": "alta",
                "observaciones": "Por favor incluir informacion del ultimo trimestre"
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "rechazar_clonacion_por_clonado",
            "actor_id": "abogado-clonado-001",
            "reason": "No cuento con la informacion solicitada",
            "data": {
                "motivo_rechazo": "La informacion solicitada no corresponde a mi area de responsabilidad"
            },
            "metadata": {
                "fecha_rechazo": "2024-12-02T09:00:00Z",
                "numero_rechazo": 1
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "responder_clonacion",
            "actor_id": "abogado-clonado-001",
            "reason": "Respuesta a solicitud de clonacion",
            "data": {
                "respuesta_clonacion": "Adjunto la informacion solicitada sobre contratos laborales vigentes del area Juridica.\n\nResumen:\n- Total contratos vigentes: 150\n- Contratos nuevos ultimo trimestre: 25\n- Renovaciones: 12",
                "documentos_adjuntos": [
                    {
                        "nombre": "Listado_Contratos_Q4_2024.xlsx",
                        "tipo": "de_gestion",
                        "fecha_cargue": "2024-12-03T10:00:00Z"
                    },
                    {
                        "nombre": "Estadisticas_Contratacion.pdf",
                        "tipo": "de_gestion",
                        "fecha_cargue": "2024-12-03T10:05:00Z"
                    }
                ]
            },
            "metadata": {
                "fecha_respuesta": "2024-12-03T10:10:00Z",
                "tiempo_gestion_horas": 24
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "reclasificar_a_pqrd",
            "actor_id": "asignador-001",
            "reason": "El tramite corresponde al flujo de PQRD, no a MinTrabajo",
            "data": {
                "motivo_reclasificacion": "Despues de analizar el contenido, se determina que es una peticion general y no un requerimiento del Ministerio del Trabajo",
                "flujo_destino": "PQRD",
                "tipo_pqrd": "peticion"
            },
            "metadata": {
                "fecha_reclasificacion": "2024-12-01T11:00:00Z"
            }
        }
    }
}

{
    "data": {
        "type": "transition",
        "attributes": {
            "event": "reclasificar_a_entes_control",
            "actor_id": "asignador-001",
            "reason": "El tramite corresponde a un ente de control diferente",
            "data": {
                "motivo_reclasificacion": "El requerimiento proviene de la Contraloria, no del Ministerio del Trabajo",
                "flujo_destino": "Entes de Control",
                "ente_control": "Contraloria General"
            },
            "metadata": {
                "fecha_reclasificacion": "2024-12-01T11:00:00Z"
            }
        }
    }
}
